insert into campus_admin_audit_log (
    module, action, target_id, target_name, action_result, detail, operator_name, created_at
)
values (
    #{module}, #{action}, #{targetId}, #{targetName}, #{actionResult}, #{detail}, #{operatorName}, now()
)

mapper.select:
select id,
       module,
       action,
       target_id,
       target_name,
       action_result,
       detail,
       operator_name,
       created_at
from campus_admin_audit_log


        and module = #{module}


        and action = #{action}


        and action_result = #{actionResult}


        and operator_name like concat('%', #{operatorName}, '%')


        and created_at >= #{startTime}


        and created_at <= #{endTime}


order by id desc
limit #{offset}, #{pageSize}

